SELECT 
    id, 
    order_id as "orderId", 
    amount, 
    reason, 
    status, 
    state_id as "stateId", 
    created_at as "createdAt"
FROM refund_requests

    AND order_id = #{orderId}
    AND status = #{status}
    AND state_id = #{stateId}

${orderby} ${pagination}

SELECT count(*) FROM refund_requests

    AND order_id = #{orderId}
    AND status = #{status}
    AND state_id = #{stateId}
